import boto3

def lambda_handler(event, context):
    sns_client = boto3.client('sns')
    
    # Extract message content and topic ARN from the event data
    message_content = event.get('message_content')
    topic_arn = event.get('topic_arn')
    
    if not message_content or not topic_arn:
        return {
            'statusCode': 400,
            'body': 'Message content and/or topic ARN are missing in the event data.'
        }
    
    # Define different notification types and their corresponding SNS message structures
    notification_type = event.get('notification_type', 'general')
    
    if notification_type == 'general':
        message_structure = {
            "default": message_content,
            "email": f"Subject: Notification\n\n{message_content}",
            "sms": message_content[:160]  # SMS messages are limited to 160 characters
        }
    elif notification_type == 'critical':
        message_structure = {
            "default": f"CRITICAL ALERT: {message_content}",
            "email": f"Subject: CRITICAL ALERT\n\n{message_content}",
            "sms": f"CRITICAL: {message_content[:156]}"  # Reserve space for critical prefix
        }
    else:
        return {
            'statusCode': 400,
            'body': 'Unsupported notification type.'
        }
    
    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message_structure['default'],
            MessageStructure='json',
            MessageAttributes={
                "AWS.SNS.SMS.SMSType": {
                    "DataType": "String",
                    "StringValue": "Transactional"  # or Promotional
                }
            },
            Message=json.dumps(message_structure)
        )
        
        return {
            'statusCode': 200,
            'body': f"Message published successfully. Message ID: {response['MessageId']}"
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': str(e)
        }